-- WorshipFlow - seed complementar convertido para PostgreSQL/Supabase
-- Origem: database/2026-06-21-seed-100-musicas-usuarios.sql
-- Senha padrao dos usuarios ficticios: Worship@123

BEGIN;

ON CONFLICT (id) DO NOTHING;

  id, nome, habilidades, status_ministerio, email, senha_hash, telefone,
  instrumento_principal, perfil, reset_token_hash, reset_token_expira_em,
  api_token_hash, api_token_expira_em, foto_perfil, foto_perfil_tipo, ministerio_id
)
SELECT
  2000 + seq.n AS id,
  'Membro Worship ' || LPAD(seq.n::TEXT, 3, '0') AS nome,
  'Disponivel para escalas, ensaios e repertorio. Perfil seed ' || LPAD(seq.n::TEXT, 3, '0') AS habilidades,
  'ATIVO' AS status_ministerio,
  'membro' || LPAD(seq.n::TEXT, 3, '0') || '@worshipflow.local' AS email,
  '$2a$10$BrPoknQJkcr8m.CYeTBWiuyGM9/6W/Psc1Mx7d.poBxmA9EkHEdNO' AS senha_hash,
  '(11) 9' || LPAD((70000000 + seq.n)::TEXT, 8, '0') AS telefone,
  (ARRAY['Vocal', 'Violao', 'Guitarra', 'Teclado', 'Baixo', 'Bateria', 'Saxofone', 'Percussao', 'Backing Vocal', 'Violino', 'Cajon', 'Midias'])[((seq.n - 1) % 12) + 1] AS instrumento_principal,
  CASE
    WHEN seq.n % 20 = 0 THEN 'LIDER'
    WHEN seq.n % 7 = 0 THEN 'MUSICO'
    ELSE 'MEMBRO'
  END AS perfil,
  NULL AS reset_token_hash,
  NULL::TIMESTAMP AS reset_token_expira_em,
  NULL AS api_token_hash,
  NULL::TIMESTAMP AS api_token_expira_em,
  NULL AS foto_perfil,
  NULL AS foto_perfil_tipo,
  (SELECT id FROM ministerios ORDER BY id LIMIT 1) AS ministerio_id
FROM generate_series(1, 100) AS seq(n)
ON CONFLICT (id) DO NOTHING;

SELECT setval(pg_get_serial_sequence('musicas', 'id'), GREATEST((SELECT COALESCE(MAX(id), 1) FROM musicas), 1100), TRUE);
SELECT setval(pg_get_serial_sequence('usuarios', 'id'), GREATEST((SELECT COALESCE(MAX(id), 1) FROM usuarios), 2100), TRUE);

COMMIT;